// // This module implements a 16-bit wide base pointer register that stores a value based on clock signals. On the falling edge of the clock, if the reset signal is deasserted, the register is cleared to zero. If the write signal is deasserted, the register updates its stored value with the incoming 16-bit writeData. The current value of the register is continuously available at the output data.
module top_module(input clock, write, reset,input [15:0] writeData,output [15:0] data);reg [15:0] basePointer; 
  always @ (posedge clock) begin 
  if (reset) 
  basePointer = 16'b0; 
  else if (write) 
  basePointer = writeData; 
  end 
  assign data = basePointer; 
 endmodule
